Code.Terraform:
```hcl
# EBS ボリュームの KMS 暗号化が有効になっている SageMaker トレーニングジョブ
resource "aws_sagemaker_training_job" "<example_resource_name>" {
  name     = "<example_resource_name>"
  role_arn = "<example_role_arn>"

  algorithm_specification {
    training_image      = "<example_ecr_image_uri>"
    training_input_mode = "File"
  }

  output_data_config {
    s3_output_path = "s3://<example_bucket>"
  }

  resource_config {
    instance_type     = "ml.m5.large"
    instance_count    = 1
    volume_size_in_gb = 10
    volume_kms_key_id = "<example_kms_key_arn>" # 重大: トレーニングEBSボリュームのKMS暗号化を有効にします
  }

  stopping_condition {
    max_runtime_in_seconds = 3600
  }
}
```
